noncompliant:
namespace NS {
    #ifndef MY_HDR
    #define MY_HDR /* Noncompliant: defining macro within namespace */
    #undef FOO /* Noncompliant: undefining macro within namespace */
    #endif
}

void function() {
    #define TEMP_MACRO 42 // Noncompliant: defining macro within function
    // use macro
    #undef TEMP_MACRO // Noncompliant: undefining macro within function
}

class MyClass {
public:
    #define CLASS_CONSTANT 100 // Noncompliant: defining macro within class
    void method();
};

compliant:
#ifndef MY_HDR
#define MY_HDR // Compliant: at global scope
#undef FOO // Compliant: at global scope
#endif

namespace NS {
    // namespace content without macro definitions
}

#define TEMP_MACRO 42 // Compliant: at global scope

void function() {
    // use TEMP_MACRO here
}

#undef TEMP_MACRO // Compliant: cleanup at global scope

#define CLASS_CONSTANT 100 // Compliant: at global scope

class MyClass {
public:
    static constexpr int VALUE = CLASS_CONSTANT;
    void method();
};
